"""Tokenisation helpers for textstats."""

PUNCT = ".,;:!?\"'()"


def tokenize(text):
    """Split text into raw word tokens on any whitespace."""
    return text.split()


def clean(token):
    """Strip specified surrounding punctuation from a token."""
    return token.strip(PUNCT)

"""Text summary statistics."""

from .helpers import clean, tokenize


def summarize(text):
    """Return word count, unique word count and average word length."""
    words = [clean(token) for token in tokenize(text)]
    words = [word for word in words if word]

    if not words:
        return {"words": 0, "unique": 0, "avg_len": 0.0}

    unique = len({word.casefold() for word in words})
    avg_len = round(sum(len(word) for word in words) / len(words), 2)
    return {"words": len(words), "unique": unique, "avg_len": avg_len}

